export const glossary: GlossaryTerm[] = [
  { term: 'AI for Good', definition: 'The application of artificial intelligence to address societal challenges in areas like health, climate, education, and humanitarian response.' },
  { term: 'Healthcare AI', definition: 'ML applications in medicine including medical imaging, drug discovery, and clinical decision support.' },
  { term: 'Clinical Decision Support', definition: 'ML systems that assist healthcare providers by analyzing patient data and clinical evidence to suggest diagnoses or treatments.' },
  { term: 'Transfer Learning', definition: 'Training a model pretrained on a large dataset on a smaller domain-specific dataset, enabling strong performance with limited labeled data.' },
  { term: 'AUC-ROC', definition: 'Area Under the Receiver Operating Characteristic curve, a threshold-independent metric measuring overall model discrimination ability.' },
  { term: 'F1 Score', definition: 'The harmonic mean of precision and recall, penalizing models that sacrifice one metric for the other. F-beta generalizes this with configurable weighting.' },
  { term: 'Large Language Model', definition: 'A neural network with billions of parameters trained on massive text corpora, capable of diverse language tasks through prompting or fine-tuning.' },
  { term: 'Hallucination', definition: 'The tendency of language models to generate fluent but factually incorrect text, a critical challenge for high-stakes applications.' },
  { term: 'Sentiment Analysis', definition: 'The computational identification of opinions, emotions, and subjective information expressed in text.' },
  { term: 'Collaborative Filtering', definition: 'A recommendation method based on finding patterns in collective user behavior to predict individual preferences.' },
  { term: 'Matrix Factorization', definition: 'A technique that decomposes the user-item interaction matrix into low-rank user and item latent factor matrices for recommendation.' },
  { term: 'NDCG', definition: 'Normalized Discounted Cumulative Gain, a ranking quality metric that rewards relevant items placed higher in a recommendation list.' },
  { term: 'Sensor Fusion', definition: 'Combining data from multiple sensor types (camera, LiDAR, radar) to create a more complete understanding of the environment.' },
  { term: 'Climate AI', definition: 'ML applications addressing climate change through weather prediction, energy optimization, and environmental monitoring.' },
  { term: 'Adaptive Learning', definition: 'Educational technology that personalizes content and difficulty based on individual student performance.' },
  { term: 'Precision Agriculture', definition: 'Data-driven farming practices that optimize resource use at fine spatial scales using ML and sensor data.' },
  { term: 'Assistive Technology', definition: 'Technology that helps people with disabilities access information and interact with their environment.' },
  { term: 'Cold Start Problem', definition: 'The challenge of making recommendations for new users or items with no prior interaction history.' },
  { term: 'RAG', definition: 'Retrieval-Augmented Generation, combining LLM generation with external knowledge retrieval to improve accuracy and reduce hallucination.' },
];

